INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5238747','Батько отаман (Три дороги стеляться)','Музика: Анатолій Сердюк Слова: Лариса Верьовка. Виконує: Анатолій Сердюк','uk','ukraine_1991',NULL,NULL,'http://smoz.ru/',NULL,'Батьку отаман, батьку отаман,
Три дороги стеляться.
Котрою скажи, батьку отаман,   |
Молодість повернеться?..       | (2)

Батьку отаман, батьку отаман,
Ой, від волі п''яні ми.
На степу туман, на душі туман, |
Молодість туманами.            | (2)

Батьку отаман, батьку отаман,
А любов нам до лиця.
В молоді літа батьку отаман,   |
Як любити хочеться.            | (2)

Батьку отаман, батьку отаман,
Що то нам пророчиться.
А життя одне, батьку отаман,
Помирать не хочеться.
А життя одне, батьку отаман,
Ой, як жити хочеться хочеться.
Батьку отаман, батьку отаман,
Ой, як жити хочеться хочеться!','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5238747'), datetime('now')),datetime('now'));
