INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5228807','Ой, чиє ж то поле','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Збірник художніх творів "Стожари" 1991 р.',NULL,'Ой, чиє ж то поле
Зажовтіло стоя?
Іванове поле
Зажовтіло стоя.
Женці молодії,
Серпи золотії!

Ой, чиє ж то поле
Задрімало стоя?
То Грицькове поле
Задрімало стоя.
Женці всі старії,
Серпи всі стальнії!

А ми свому пану
Ізробили славу:
Житечко пожали,
В снопи пов''язали,
У копи поклали.

Ой, ми свому пану
Ізробили славу!
Ой, паноньку наш,
Обжиночків час!','[''pisni.org.ua'', ''cat:obzhynkovi'', ''Обжинкові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5228807'), datetime('now')),datetime('now'));
