INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5232747','Гімн Євро-2012','Слова: Микола Джумак','uk','ukraine_1991',NULL,'2012','авторське подання',NULL,'"Ще не вмерла Україна!"
"Іще польска не сгінела!"
Підіймають дві країни
Стяг футболу аж до неба!

Приспів:
Футбол, футбол, футбюол!
Фінал Європи знов
Зібрав на поле всіх,
Хто став сильнішим в грі!
Футбол, футбол, футбол!
Життя твоє - це гол!
Скандує стадіон -
Живе хай чемпіон!

"Ще не вмерла Україна!
"Іще польска не сгінела!"
Два народи всі країни
Зустрічають так у себе!

Приспів.

І квітуча Україна
І вся Польша в цю годину
Слави, честі й перемоги
Всім бажають до знемоги!

Приспів.','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5232747'), datetime('now')),datetime('now'));
