INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5252242','Крутянська пісня','Слова: Богдан-Ігор Антонич','uk','ukraine_1991',NULL,'2012','Інформаційний бюлетень ІКААПУ Інформ №28 (218) 2012 рік.',NULL,'Спом''янімо в пісні славу Крутів,
Найсвятіше з наших бойовищ!
Крути! Крути! - смолоскип в майбутнє.

Крути! Крути! Це за Батьківщину
Стати муром, шанцем душ і тіл.
Крути! Крути! Мужньо, воєдино
Прямувати в найсвятішу ціль.

Крути! Крути! Час розплати близько,
Вже червоний ворог кари жде.
Крути! Крути! Вічне бойовисько
За майбутнє, за світліший день.

Крути! Крути! Мужність і посвята,
Вірність, що міцніша понад смерть
Крути! Крути! Горда і завзята
Кличе пісня і веде вперед.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5252242'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5252242','Крутянська пісня','Спом''янімо в пісні славу Крутів,
