INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_525704','Дай, Боже, радості','Музика: Геннадій Татарченко Слова: Андрій Демиденко. Виконує: Назарій Яремчук, Павло Мрежук','uk','ukraine_1991',NULL,NULL,'Пісні Назарія Яремчука. "Бібліотека українця", Київ, 1995.',NULL,'У білої заздрості - біла печаль,
У чорної - чорний весь світ.
У білої заздрості - щирість в очах,
У чорної - схована злість.
У білої заздрості - друзі і день,
У чорної - зрада і ніч.
У білої заздрості - віра в людей,
У чорної - сотні облич...

Приспів:
Дай, Боже,
До старості
Не знати
Чорної заздрості.
Дай, Боже,
Не заздрить нікому.
Дай, Боже, радості,
Світлої радості
Кожному серцю
ї кожному дому!

Збагне біла заздрість біль наших утрат
І втішить у годину біди.
А чорная прийде, обійме, як брат,
Але порадіє завжди.
У білої заздрості - друзі і день,
У чорної - крик самоти.
Між ними ніколи не звести мости.
Між ними - довічна будель!

Приспів.','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_525704'), datetime('now')),datetime('now'));
