INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5260949','Співанка','Музика: Оксана Первова-Рошка Слова: Віктор Кучерук. Виконує: Анастасія Ілащук','uk','ukraine_1991',NULL,NULL,'інтернет','Шукаю мінус.','Обрій підрум''янений світанком
І хмарок ватаги в висоті, -
Розбудила мамина співанка,
А не сонця хвилі золоті.
Світлим святом та у сірий будень,
Настроєм веселим чи сумним, -
Завжди душу піснею голубиш,
Зігріваєш голосом дзвінким.

Приспів:
Я тобі посію біля хати
Чорнобривці прямо під вікном.
Це ж про них так любиш ти співати,
Що і я підспівую слідком.

Зрощенні у сонячнім промінні,
Мов жаринки ватри спалахнуть.
За труди й невидиме терпіння
Ними уквітчаю твою путь.
Розбуди і завтра на світанні,
Прожени із хати тихий сум.
Я люблю твої співанки ранні,
Крізь усе життя їх пронесу!

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5260949'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5260949','Співанка','Обрій підрум''янений світанком
