INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5264807','Соловей, соловейко!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Соловей, соловейко!
Ой чий же то клин та й не виораний?
Соловей, соловей...

Соловей, соловейко!
Там Микола й орав
Та й плуг поламав.
Соловей, соловей...

Соловей, соловейко!
Та й плуг поламав
І воли погубив.
Соловей, соловей...

Соловей, соловейко!
І воли погубив,
До Галочки приблудив.
Соловей, соловей...

Соловей, соловейко!
Як од Галочки йшов,
І воли знайшов.
Соловей, соловей...

Соловей, соловейко!
І плуг поладнав,
І клин доорав.
Соловей, соловей...','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5264807'), datetime('now')),datetime('now'));
