INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_52601','Соколи','Виконує: Акорд','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Гей десь там де чорні води,
Сів на коня козак молодий.
Плаче молода дівчина,
Їде козак з України.

Приспів:
Гей, гей, гей, соколи,             |
Оминайте гори, ліси, доли.         |
Дзвінь, дзвінь, дзвінь, дзвіночку, | (2)
Степовий жайвороночку.             |

Жаль, жаль, за милою,
За рідною стороною.
Жаль, жаль, серце плаче,
Більше її не побачу.

Приспів.

Плаче, плаче, дівчинонька,
Люба моя ластівонька.
А я у чужому краю,
Серце спокою не має.

Приспів.

Меду ви нам наливайте,
Як загину - поховайте.
На далекій Україні,
Коло милої дівчини.

Гей, гей, гей, соколи,                |
Оминайте гори, ліси, доли.            |
Дзвінь, дзвінь, дзвінь, дзвіночку,    | (2)
Степовий жайвороночку.                |
(Мій степовий дзвінь, дзвінь, дзвінь) |

Гей, гей, гей, соколи,                |
Оминайте гори, ліси, доли.            |
Дзвінь, дзвінь, дзвінь, дзвіночку,    | (2)
Степовий жайвороночку.                |
