INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_52601','Соколи','Гей десь там де чорні води,
Сів на коня козак молодий.
Плаче молода дівчина,
Їде козак з України.

Приспів:
Гей, гей, гей, соколи,             |
