INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5271405','Якщо ми любимо','Музика: Володимир Шинкарук Слова: Володимир Шинкарук. Виконує: Володимир Шинкарук','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Вже літо моє відлетіло з громами,
Але для печалі немає підстав -
Каюсь я, друзі мої, перед вами,
Що в радості часто про вас забував.

Приспів:
Іще не все збулось, а серце болить чогось,
Перший осінній дощ мої цілує губи.
Якщо ми любимо - ми повертаємось,
Ми повертаємось - якщо ми любим.

Минає життя між піснями й сльозами,
І серце моє, і душа на розрив -
Каюсь я, друзі мої, перед вами,
Що рідко заходив, не часто дзвонив.

Приспів.

Між нами роки і дороги між нами,
Розлуки і зустрічі, сонце і сніг,
Каюсь я, друзі мої, перед вами,
В усьому, що я для вас зміг... і не зміг.

Приспів.','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5271405'), datetime('now')),datetime('now'));
