INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5271106','Хрест Христовий знявся в вись',NULL,'uk','ukraine_1991',NULL,NULL,'Пісенник молодіжної спільноти церкви святого Миколая на Аскольдовій Могилі. - м. Київ. - 2011.',NULL,'Хрест Христовий знявся в вись,
Перехожий зупинись!
Глянь на Спаса, Він терпить,
Для душі спасенна мить.

Хрест Христовий знався в вись,
Божій Матері вклонись.
Помирає любий Син,
Він у Неї лиш один.

Хрест Христовий знявся ввись,
Тіла й крові доторкнись.
Смертю Бог отворить ад,
тобі - небесний сад.','[''pisni.org.ua'', ''cat:strasni'', ''Страсні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5271106'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5271106','Хрест Христовий знявся в вись','Хрест Христовий знявся в вись,
Перехожий зупинись!
Глянь на Спаса, Він терпить,
Для душі спасенна мить.

Хрест Христовий знався в вись,
Божій Матері вклонись.
Помирає любий Син,
Він у Неї лиш один.

Хрест Христовий знявся ввись,
Тіла й крові доторкнись.
Смертю Бог отворить ад,
тобі - небесний сад.');
