INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5272646','Зібрались сьогодні в урочистий час','Музика: Галина Васіна Слова: Олена Скиба, Галина Васіна','uk','ukraine_1991',NULL,NULL,'інтернет',NULL,'Зібрались сьогодні в урочистий час.
Дає нам Вкраїна суворий наказ:
Учитись, дружити в єдиній сім''ї,
І дружбу й знання крізь роки пронести!

Приспів:
Щоб цвіла Україно моя,
Ми даємо обіцянку нині:
Вчитись так, щоб набуті знання
Знадобились моїй Батьківщині!

Сіяють нам Лесі досвітні вогні,
Шевченкові думи у серці живі,
І ми крізь життя пронесем урочисто
Високе й почесне звання гімназиста!

