INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5276545','Моя мама','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Від степів до гір високих,
Ген за обрій пролягла,
Синь небес рясним колоссям,
Рідна батьківська земля.
З Божого благословення
Й материнського тепла
Тарувала в світ пісенний
Мені доленьку весна!

Приспів:
Я до тебе, моя мамо,
Як в дитинстві притулюсь,
На світанку, рано-вранці,
Я за тебе помолюсь.
І попрошу в Бога ласки,
Неба чистого блакить,
Щоб в житті мені не впасти,
Так, як ти учила жить.

Дарувала мені ненька
Своє серце золоте
І любити научила те,
Що рідне й дороге:
Мову нашу колискову
Й нашу земленьку святу
І молитви щире слово
Я навіки збережу.

Приспів.

І попрошу в Бога ласки,
Неба чистого блакить,
Щоб в житті мені не впасти,
Так, як ти учила жить.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5276545'), datetime('now')),datetime('now'));
