INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5277704','Дзвоник прощальний','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Прощай же, рідна школо,
Прощай, мій рідний край,
Дзвінка чарівна мово,
Не край сердець у нас.

Приспів:
Дзвоник прощальний -
Музика дум,
Дзвоник прощальний -
Радість і сум.

Прощайте, милі друзі,
Прощайте, вчителі,
За міць в новій дорозі
Уклін Вам до землі!

Приспів.

З очей сльоза зринає
І мріям навздогін
Дзвенить і серце крає
Шкільний прощальний дзвін.

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5277704'), datetime('now')),datetime('now'));
