INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5280106','Я - школярка','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я крокую по стежині,
Бо школярка я віднині,
І сміються в небі синім
Промінці.
Я весела і завзята,
Бо сьогодні в мене свято
І тримаю я портфелик у руці!

Приспів:
Сонечко у небі,       |
Усмішки довкола,      |
Нам навчатись треба - |
Ми йдемо до школи!    | (2)

Я крокую по стежині,
А у серці пісня лине
І веселка кольорова
Розцвітає.
В небі сонечко сміється,
А від щастя б''ється серце -
То мелодія дитинства золота.

Приспів. (2)','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5280106'), datetime('now')),datetime('now'));
