INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5285545','Веснянка','(Травонько, ти, травонько). Музика: В. Таловиря Слова: Володимир Ладижець','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Травонько, ти, травонько,
Зеленись,
Золотому сонечку
Поклонись,
Щоб розквітла яблунька
На горі,
Щоб гулялось весело
Дітворі!

А ми того сонечка
Промінці
Упіймаєм решетом
У ріці.
Заплетем у коси їх,
Мов стрічки,
Ой хороші ж матимем
Кіснички!

Зеленись же, травонько,
Зеленись,
Разом з нами сонечку
Поклонись!','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5285545'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5285545','Веснянка','Травонько, ти, травонько,
Зеленись,
