INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_528704','Твоя країна','Музика: Едуард Приступа Слова: Росава. Виконує: Росава','uk','ukraine_1991',NULL,'2005','довгий себастіан','Пісню надав: довгий себастіан (гість) (rseniv@gmail.com) 18.10.2005 01:13 Коментар від "довгий себастіан": "...я граю так як [тут], але можна в іншій тональності (c f c g). можна ще якось по іншому - як кому звучить..."','Відірвавшись вранці зі свого ліжка,
Ти сказав: вже досить - потрібні зміни!
Голова - на плечах, цілі - прогресивні,
Треба взяти в руки справи в Україні!
Твоє слово - варте, в ньому воля й сила,
Коли ти мовчиш - не сподівайсь на диво!
Щоб змінити світ - починати з себе,
A#
.... Я вірю у тебе!
Це моя країна - рідна Україна,
Це твоя країна - наша Україна.
Де б і ким не був ти - залишайсь собою,
Що було - минуло, змило все водою!
Починай життя з нової сторінки,
Твори цей світ, він - це твої вчинки!
Зазирни в майбутнє - це ж бо твої мрії,
Об''єднаймось браття - спільні в нас надії!
В рішеннях і діях покладайсь на себе,
Ти зможеш, я вірю у тебе!
Це моя країна - рідна Україна,
Це твоя країна - наша Україна.
Молодь ця нікчемна, вона зіпсута,
Та це не про нас, ми - вільні, розкуті!
Хочемо бути почуті ми, це - Україна,
Ми є майбутнє!
Це моя країна - рідна Україна,
Це твоя країна - наша Україна.','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_528704'), datetime('now')),datetime('now'));
