INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5284302','Повертайся живим','(Ти, головне, повертайся додому). Музика: Kozak System, Сестри Тельнюк Слова: Ірина Цілик, Kozak System, Сестри Тельнюк. Виконує: Kozak System, Сестри Тельнюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ти, головне, повертайся додому,
Врешті знімай запилюжені берці
І вчися наново жити потому
З перепрошитою вірою в серці...
Ти, головне, повертайся, здолавши
Чистого зла непрожований стогін,
І відпускай цю ненависть назавше
Посеред мирної тиші густої.

Приспів:
Ти повертайся, ти головне повертайся,
Ти головне повертайся живим!..
Ти повертайся, ти головне повертайся,
Ти головне повертайся живим!..

Ти, головне, повертайся тим шляхом,
Що вбереже твої душу і тіло.
Чорна земля із розпеченим пахом
Тільки дощу, а не крові хотіла.
Ти, головне, повертайся до мами.
Десь там сивіючи за видноколом,
Матері тужать і дружать домами,
Що пахнуть ніжністю та корвалолом.

Приспів.

Ти, головне, повертайся назовсім
І народи-посади-споруди, а
Вже у твоєму дитиську курносім
Виросте радість, нова і правдива.
Ні, ця війна не потрібна нікому.
Так, ми її не пробачимо, себто
Перемагай і вертайся додому.
Просто живим повертайся, і все тут!

Приспів. (2)

Ти повертайся, ти головне повертайся,
Ти головне повертайся живим...','[''pisni.org.ua'', ''cat:devoted'', ''cat:patriotic'', ''Пісні присвячені окремим особам'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5284302'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5284302','Повертайся живим','Ти, головне, повертайся додому,
