INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5272343','Чудова Судова','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Патріотичні пісні. Пісні з Галичини. Пісню виконує гурт Олега Івашка (м. Судова Вишня).','Тобі я сьогодні скажу,
Про все, що так вірно кохаю,
Тебе я так довго люблю,
Бо кращих від тебе не знаю.
Жіноча натура твоя,
У мріях злітає до неба,
Деінде поїхав би я,
Та як мені жити без тебе,

Приспів:
Чудова, чудова,   |
Як пісня солов''я, |
Судова, Судова,   |
Судова Вишня моя! | (2)

В Парижі каштани цвітуть,
Варшавою панни гуляють,
Але не туди моя путь -
Мене там повік не чекають,
Мені та стежина свята,
Котрую матуся ступає,
Вона лиш у мене одна
І іншої я не шукаю.

Приспів.

Промовить щось Спаська гора,
І чує гора Комарова,
У відповідь Трійця Свята,
Шле дзвонів величну розмову.
Нехай же повік не мина,
Усе що злітає до неба,
А книга життя лиш одна,
Її прочитати нам треба.

Приспів. (2)','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5272343'), datetime('now')),datetime('now'));
