INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5289444','До нас приходить Новий Рік!','Слова: З. Петрова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Добре, що кожен рік
До нас приходить Новий рік,
Запалює нашу ялинку
І заводить хоровод.

Приспів:
Якщо танцю буде мало,
Є у танцю поворот:
Ми станцюємо все спочатку
А потім - навпаки.

А, ну, ширше, ширше коло,
Виходь сміливіше, друже!
Веселіше плескай у долоні,
Не шкодуй сьогодні рук!

Приспів.

Ми під ялинкою танцювати
Можемо цілих три години,
І анітрохи не втомимося -
Ось такі дива!

