INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5295106','Богу співайте нову піснь',NULL,'uk','ukraine_1991',NULL,NULL,'християнський пісенник',NULL,'Розкаже пісня ця
Про діла Його рук,
І про Отця, що маєм
В небі над нами.

Приспів:
Богу співайте нову піснь,
Співом славте Його честь,
Бог вчинив великі чуда
Серед нас.

Він Сина свого дав,
Щоб всіх людей спасти,
І небеса відкрив
Для дітей Божих.

Приспів.

Виявив свою міць
В Пасхальну святу ніч
І возвеличив Сина,
Що воскрес із мертвих.

Приспів.

З Ним воскресив і нас,
Очистив серця в нас,
В тих, що Йому звірились,
Любов розпалив.

Приспів.','[''pisni.org.ua'', ''cat:voskresni'', ''Воскресні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5295106'), datetime('now')),datetime('now'));
