INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_529003','Жарівка *','Музика: Олесь Дяк Слова: Андрій Панчишин. Виконує: Олесь Дяк','uk','ukraine_1991',NULL,NULL,'Аудіо-CD "Олесь Дяк. "Магія Львова" (2002)','Текст і акорди записано на слух з аудіо-джерела. Акорди подано спрощено. Тональність оригінальна. Підбір акордів: bohdanko (pisni.org.ua)','На вулиці Вірменській
