INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_529302','За Сибіром Сонце сходить Хлопці не зівайте','Українська народна пісня. Виконує: Сергій Фоменко','uk','ukraine_1991',NULL,'2000','1. Співає Сергій Фоменко (Фома, гурт "Мандри"): сл. Тимка Падури (як подано на кружалі) або Ян Комарницького, як подано тут — http://www.library.vinnitsa.com/publications/2000/print/vindates2000.html, муз. народна. — Дух не вмирає, дух не згасає. Олег Скрипка презентує пісні барикад. Пісні Помаранчевого повстання. Кружало, 2005. 2. Українські народні пісні. - К.: Мистецтво, 1965. 3. Перлини української нардної пісні. - К.: Музична Україна, 1989. 4. http://poetry.uazone.net/kozak17.html','ВІННИЧЧИНА В ДАТАХ — http://www.library.vinnitsa.com/publications/2000/print/vindates2000.html — 1801, 21 грудня, - народився Тиміш Падура (1801, м. Іллінці, -1871, м. Козятин, похований у м. Махнівці, нині с. Комсомольське Козятин. р-ну), польський і український поет, музикант, революціонер. Навчався у Вінницькій гімназії.... — 1784 - народився Ян Комарницький (1784, Брацлавщина, - 1840), католицький священик, польський і український поет, імовірний автор пісні "За Сибіром сонце сходить". Тарас Шевченко і Вінниччина — http://www.library.vinnitsa.com/publications/2004/shevchenko.html — Кам''янець-Подільський зацікавив поета насамперед своєю старою фортецею на урвистому березі Смотрича, в якій тричі був ув''язнений Устим Кармалюк. Про "Славного лицаря", як назвав Шевченко керівника селянського руху на Поділлі, він ще в дорозі почув немало спогадів і переказів. А в Кам''янці-Подільському П.Чуйкевич 3 жовтня 1846 р. записав йому в альбом кілька народних пісень, серед них "– Ой Кармалюче, по світу ходиш". Про інтерес поета до постаті У.Кармалюка свідчить його запис у "Журналі" ("Щоденнику") від 20 травня 1858 р., тут же він подав текст пісні "За Сибіром сонце сходить"..... — У поемі "Варнак" і однойменній повісті, малюючи образ кріпака, що став на шлях помсти панам, Т.Шевченко використав деякі факти й сюжетні лінії, пов''язані з діяльністю У.Кармалюка. Варто, однак, прислухатися до думки В.У.Олійника, який у статті "До питання про використання Шевченком фольклорних матеріалів про Кармалюка" слушно зауважив: "Коли вже говорити про відтворення образу Кармалюка в поезії Шевченка, то не в поемі "Варнак" треба його шукати, а швидше в вірші "Ой виострю товариша", написаному в тому ж 1848 р. вже на Кос-Аралі. У цьому вірші Шевченко створює образ повстанця, шукача правди, що як і Кармалюк, за народною піснею, "понад шляхами" переймає багатіїв. Цей вірш не тільки змістом, а й будовою строфи – 2 (8+6) – та розповіддю від першої особи нагадує відому народну пісню про Кармалюка "Повернувся я з Сибіру" [12].... — 18. Щоденник // Повне зібр. тв.: В 6 т. – К., 1964. – Т. 5. Щоденник. Автобіографія. – С. 7-245. – Із змісту: [Запис Т.Шевченком у щоденнику пісні про У.Кармалюка "Повернувся я з Сибіру"]. – С. 243-244.... — 76. Народ про Кармалюка: Зб. фольклор. матеріалів. – К.: Вид-во АН УРСР, 1961. – 276 с. – Із змісту: [Про пісню "Повернувся я з Сибіру" та ставлення до неї Т.Шевченка]. – С. 253-254.... — 252. Лісовий П.М. Тарас Шевченко про Томаша Падуру // Тези доп. VІІ Вінниц. обл. краєзн. конф. – Вінниця, 1989. – С. 25-26. — 253. Бабенко І. Наш земляк поет Тимко Падура // Трудова слава (Іллінці). – 1987. – 14 жовт. — 254. Падура Тимко // Шевченківський словник: У 2 т. – К., 1977. – Т. 2. – С. 76-77. — 255. Пилинчук Р.Я. Падура Тимко // УРЕ. – 2-е вид. – К., 1982. – Т. 8. – С. 126-127. Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Господа Милосердного прохали та благали. Хоч здається не в кайданах а все ж не на волі. Заплакала Україна така її Доля. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','За Сибіром Сонце сходить... Хлопці, не зівайте:
Ви на мене, Кармалюка, всю надію майте!           | (2)

Повернувся я з Сибіру, та не маю долі:
Хоч, здаєцця, не в кайданах, та все ж не на волі. | (2)

Маю жінку, маю діти, та я їх не бачу!
Як згадаю про їх долю — гірко сам заплачу!        | (2)
Асесори, і поліцаї справники за мною ганяють, —
Більше ж вони людей вбили, як я гріхів маю!       | (2)
За Сибіром Сонце сходить... Хлопці, не зівайте:
Ви ж на мене, Кармалюка, всю надію майте!         | (2)

За Сибіром сонце сходить... Хлопці, не зівайте:
Ви на мене, Кармалюка, всю надію майте!

Повернувся я з Сибіру, та не маю долі:
Хоч, здається, не в кайданах, а все ж не на волі.

Маю жінку, маю діти, та я їх не бачу!
Як згадаю про їх долю — сам гірко заплачу!

Куди піду, подивлюся — скрізь багач панує,
У розкошах превеликих і днює й ночує.

Убогому, нещасному — тяжкая робота,
А ще гіршая неправда — вічная скорбота!

Зібрав собі славних хлопців... Що ж кому до того?
Засідаєм при дорозі ждать подорожнього.

Чи хто іде, чи хто їде, Так час нудно ждати,
Що не маю пристанища ані свої хати.

Асесори, ісправники за мною ганяють, —
Більше ж вони людей вбили, як я гріхів маю!

Зовуть мене розбійником, що людей вбиваю, —
Я багатих убиваю, бідних награждаю.

З багатого хоч я візьму — убогому даю:
А так гроші розділивши, гріха я не маю','[''pisni.org.ua'', ''cat:istorychni'', ''cat:nostalgia'', ''cat:philosophic'', ''cat:povstanski'', ''cat:suspilno-politychni'', ''Історичні пісні'', ''Пісні з ностальгічними мотивами'', ''Філософські пісні'', ''Повстанські пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_529302'), datetime('now')),datetime('now'));
