INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5297807','На Івана, на Купала','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'На Івана, на Купала,
Що Іван діє?
Гречку сіє.

У нашої гречки
Гарні вершечки.
Було б тобі, Іванку,
Не купатися,
Було б тобі, Іванку,
З нами гратися.

Що Іван діє?
Пшеницю сіє.

У нашої пшениці
Жовті косиці.
Було б тобі, Іванку,
Не купатися,
Було б тобі, Іванку,
З нами гратися.','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5297807'), datetime('now')),datetime('now'));
