INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_52949','Пироги','Виконує: Віктор Пашник','uk','ukraine_before_1917',NULL,NULL,'Полум''я (часопис тернопільських пластунів). Співаник.',NULL,'Служив козак при війську,
Мав років 23,
Любив він дівчиноньку
І з сиром пироги.

Чи з сиром, чи без сиру,
Чи з житньої муки,
Чи теплі чи холодні,
А лиш би пироги.

Ішов він раз по стежі
Ранкової пори
І стрінув дівчиноньку,
Що несла пироги.

Дівча моє хороше,
Чи знаєш мої сни,
Що я тебе кохаю
І з сиром пироги.

Дівчина як почула,
Козацькі мрії-сни -
Відразу запросила
На свіжі пироги.

І як вони діждались
Щасливої пори -
Вона його цілує
А він їсть пироги.

Та раптом із-за лісу
Взялися вороги,
Козак із переляку
Сховався в бур''яни.

А то були мисливці -
Ніякі вороги,
Взяли собі дівчину
І з сиром пироги.

Козак гірко заплакав,
- О, люті вороги,
Візьміть собі дівчину -
Віддайте пироги.

Ой, чули, чули люди,
Ой, чули, чули ви,
Ніколи не міняйте
Любов на пироги.','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_52949'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_52949','Пироги','Служив козак при війську,
Мав років 23,
Любив він дівчиноньку
І з сиром пироги.

Чи з сиром, чи без сиру,
Чи з житньої муки,
Чи теплі чи холодні,
А лиш би пироги.

Ішов він раз по стежі
Ранкової пори
І стрінув дівчиноньку,
Що несла пироги.

Дівча моє хороше,
Чи знаєш мої сни,
Що я тебе кохаю
І з сиром пироги.

Дівчина як почула,
Козацькі мрії-сни -
Відразу запросила
На свіжі пироги.

І як вони діждались
Щасливої пори -
Вона його цілує
А він їсть пироги.

Та раптом із-за лісу
Взялися вороги,
Козак із переляку
Сховався в бур''яни.

А то були мисливці -
Ніякі вороги,
Взяли собі дівчину
І з сиром пироги.

Козак гірко заплакав,
- О, люті вороги,
Візьміть собі дівчину -
Віддайте пироги.

Ой, чули, чули люди,
Ой, чули, чули ви,
Ніколи не міняйте
Любов на пироги.');
