INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5299302','Повстанець','Музика: народна Слова: Landser, Нестор (Вiталiй Нестерчук), Арсенiй Бiлодуб. Виконує: Андрій Середа, Арсеній Білодуб','uk','ukraine_1991',NULL,NULL,NULL,'ВСТУП: Am |--------------------------------------| |------------------1-------------------| |--------------2-------2--------2-----| |------------2---2---2---2----2---2--| - 2 рази |------0-3-0----------------0---------| |--0-3---------------------------------| Am G Я був Повстанцем в козацькій борні C E Славного Богдана в визвольній війні. Am C G Навіть на страту з мужністю йшов Am G Am Я був Повстанцем, за свободу лив кров.... Am C Am Так, я Повстанець, і кипить моя кров. C G Я повстав – за свободу Am Тече моя кров. Виконує: Андрій Середа {180}, Арсеній Білодуб Альбом:','Я був Повстанцем в козацькій борні
Славного Богдана в визвольній війні.
Навіть на страту з мужністю йшов
Я був Повстанцем, за свободу лив кров!

Я був сотником у Залізняка,
В гайдамацьких загонах гартувалась рука,
Крізь огнисту бронь йшли до бою ми знов:
Я був Повстанцем, за Правду лив кров!

Я був Чорним Вороном, подібним до тіні,
У Холодного Яру в останній годині.
Хто ворогу здався, кого страх поборов -
Прийде Повстанець і проллє вашу кров!

Я був Лісовим Братом на Волині,
До кінця опирався червоній лавині...
Від безсилої люті скаженів людолов,
Я - Повстанець!

Двадцятого Лютого на Майдані...
Проти снайперів, "беркуту" та поліцаїв!
Так добре напалм на броні запалав!
Я повстав, за свободу свою кров проливав...

Я Повстанцем залишуся аж до загину,
Не прогнати мене із моєї Країни!
Щоб зрадницький виплід у пекло зійшов
Я воюю на Сході - кипить моя кров.

Так, я Повстанець, і кипить моя кров.
Я повстав - за свободу
Тече моя кров!..','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5299302'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5299302','Повстанець','Я був Повстанцем в козацькій борні
