INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_532003','Чарівна Нічка Землю вкрила','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Правой ручкою обняла ще й поцілувала. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Чарівна Нічка Землю вкрила
Зірки на Небі мерехтять
Всюди тихенько лиш легесенько
Листки на Деревах тремтять
А Соловейко на Ліщині чарівні трелі підійма
Своїй Дружині своїй єдиній
Кохання Пісню Він співа

Приспів: Ах Соловію чом я так співать не вмію
І не зумію її Серденько приєднать
Я вечорами хотів би своїми Піснями
Ген під Вишнями їй про Кохання розказать

В той час Кохана жду на Тебе
Я жду щоб висказать Тобі
Моє Кохання мої Бажання
Мої думки мої жалі
Тебе пригорну я до себе
Німий Цілунок нас з''єдна
Про світ забудем і слухать будем
Як Соловій в Гаю співа

Приспів.','[''pisni.org.ua'', ''cat:vesilni'', ''cat:vesnyanky-hayivky'', ''Весільні пісні'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_532003'), datetime('now')),datetime('now'));
