INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5327508','Зелений гай, пахуче поле в тюрмі приснилося мені','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1930',NULL,'Уснословесний жанр повстанська пісня Місце побутування смт Запитів, Кам''янка-Бузький район, Львівська область Респондент Максимишин Марія Олексіївна, 1930 р.н. Збирачі Вовчак Андрій, Мартиник Соломія','Зелений гай, пахуче поле
В тюрмі приснилося мені,
Що степ широкий, наче море,
І втихся сум по кружині.

Сниться мені садок вишневий,
Моя хатина край села,
І в хаті тій змарніла мати,
І знудьгувалася сестра.

Сниться мені, що я на волі,
Що Україна вже вільна,
Що місто Київ вже столиця!
Що провалилася Москва.

А я, зажурений, дивлюся,
Що я ще досі у тюрмі,
І сам не знаю, чи діждуся
Те, що приснилося мені...    Наспівує Максимишин Марія Олексіївна, 1930 р.н.,смт Запитів, Кам''янка-Бузький район, Львівська область','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5327508'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5327508','Зелений гай, пахуче поле в тюрмі приснилося мені','Зелений гай, пахуче поле
В тюрмі приснилося мені,
Що степ широкий, наче море,
І втихся сум по кружині.

Сниться мені садок вишневий,
Моя хатина край села,
І в хаті тій змарніла мати,
І знудьгувалася сестра.

Сниться мені, що я на волі,
Що Україна вже вільна,
Що місто Київ вже столиця!
Що провалилася Москва.

А я, зажурений, дивлюся,
Що я ще досі у тюрмі,
І сам не знаю, чи діждуся
Те, що приснилося мені...    Наспівує Максимишин Марія Олексіївна, 1930 р.н.,смт Запитів, Кам''янка-Бузький район, Львівська область');
