INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5328704','Несе теща воду, коромисло гнеться','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1954',NULL,'Уснословесний жанр родинно-побутова пісня Місце побутування с. Вовче, Вовченська сільрада, Турківський район, Львівська область Респондент Федьків Люба Василівна, 1954 р.н. Збирачі Винницька Ліля, Кльок Юлія','Несе теща воду, коромисло гнеться,
А зять на порозі стоїть та й сміється:  | (2)

- Неси швидше воду, бо нічим умиться,
Ідеш, шкандибаєш, противно дивиться.    | (2)

Як принисеш воду, рубай швидше дрова,
Щоб через годину вечеря готова.         | (2)

Не буде півлітри, то вигоню з хати,
Будеш під забором всю ніч ночувати.     | (2)

- Ой, зятю, мій зятю, який ти хороший,
Чом не виганяв''їс, як давала''м гроші?   | (2)

Як давали гроші, ви були хороші,
А як перестали, та й мене прогнали.     | (2)

Ой, куди я піду, як нема вже хати?
Нема ні куточка, ніде переспати.        | (2)

- Ой, маю я діток: дві дочки і сина,
Вийди, мамо, з хати, бо ти нам причина. | (2)

А ти йди до сина, в нього більші хати,
Будеш там і жити, бо ти його мати.      | (2)

- Діти, мої діти, не межуйте мною,
Викопайте яму мені з головою.           | (2)

Викопайте яму, та й не споминайте,
Скажіть своїм дітям, так і нас ховайте. | (2)','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5328704'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_5328704','Несе теща воду, коромисло гнеться','Несе теща воду, коромисло гнеться,
А зять на порозі стоїть та й сміється:  | (2)

