INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5326601','Не сумуй...','Музика: Дмитро Гарбуз Слова: Володимир Пуряєв','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Дмитро Гарбуз.','Прийшла весна і квіти розцвітають,
Згадаю я, як вдома дітки грають,
Любов моя, ти не сумуй за мене,
А збережи моє кохання в себе.
Доки війна, я буду захищати,
Любов моя, країна - наша мати!
За хлопців всіх, які лягли за тебе,
Захисники: Їх пам''ятати треба!
Ти не сумуй!.. Ти не сумуй!..
Ти не сумуй!.. Ти не сумуй!..

Настане день - і прийде наша слава,
А поки ми - захисники держави,
І командир нам скаже: Всім до бою!
Ми віддамо своє життя за волю!
Вже сил нема, але ми не здаємось,
Дрижить земля, а значить, не присниться
Любов моя, яка сумує знову!..
Ти не сумуй! Я скоро буду вдома!
Ти не сумуй!.. Ти не сумуй!..
Ти не сумуй!.. Ти не сумуй!..
