INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5332900','Україна','Музика: Віталій Кобринович Слова: Віталій Кобринович. Виконує: Гурт МалДіви','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Запам''ятати дуже легко ці слова,
Так само легко як своє ім''я.
Ми тут живемо, де цвітуть сади й поля,
Де мова українська рідна!
Дякуєм богу, що зростаєм тут,
І що у нас такі батьки!
За чисте небо, за родючий грунт
Серцем ми співаємо ці рядки!

Приспів:
На Україні, на Україні
Виростають крила!
Бо українці, всі українці -
Єдина родина!
На Україні, на Україні
Щасливі дівчата!
Бо українці, лиш українці
Вміють так кохати!

В карпатських горах,
Як хоч раз ти побував,
Завжди, повір, повернешся сюди!
Якщо ти Україну ненькою обрав,
То збагатів душею назавжди!
Дякуєм богу, що зростаєм тут
І що у нас такі батьки!
За чисте небо, за родючий грунт
Серцем ми співаємо ці рядки!

Приспів','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5332900'), datetime('now')),datetime('now'));
