INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5333242','Мій тато - герой','Музика: Тетяна Піскарьова Слова: Роман Біль. Виконує: Тетяна Піскарьова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вона мене щовечора питає,
Коли повернеться її татусь,
Зі слізками на очках засинає,
А я всю ніч молюсь, молюсь...
Будь-ласка, повертайся вже додому,
Ти нам потрібен більше ніж життя,
Не смій віддати ти своє життя нікому,
Бо ти - татусь, вона - твоє дитя!

Приспів:
Я - твоя доня, щастя в долонях,
Ти повернешся - я пригорнусь!
Тату рідненький, ти так близенько,
Приїдь до мене, ти - мій татусь!

А вранці знову поглядом шукає
І з сумом поглядає у вікно,
Цукерку на сніданку залишає
Для свого тата рідного!..
Надію це щодня мені вселяє,
Я прошу Бога тільки не знедоль,
Та наша доня гордо промовляє:
Я знаю, мій татусь - герой!

Приспів.

Речитатив:
Вона мене щовечора питає,
Коли повернеться її татусь,
Зі слізками на очках засинає,
А я всю ніч молюсь, молюсь,
Молюсь...
Донечко, щоби ти хотіла сказала
Зараз татові?
Будь-ласка, повертайся вже додому!
Коханий, ми чекаємо на тебе!..
А я знаю, мій тато - герой!
Так, рідна моя, твій татусь - герой!..','[''pisni.org.ua'', ''cat:ato'', ''cat:pro-batkiv'', ''Пісні російсько-української війни та АТО'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5333242'), datetime('now')),datetime('now'));
