INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5337747','Солов''їна Україна','Музика: Сергій Бондаренко Слова: Валентина Полинок. Виконує: Валерія Лизогуб','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Валерія Лизогуб.','Київ привітний, сонячне небо
Нам дарують парки та сквери.
Зоряний простір, степ України
Все з''єднала диво - країна!

Приспів:
Солов''їна Україна
Це клондайк для всіх!
Солов''їна Україна -
Творчий оберіг!
Під пісенним небом
Всіх дітей твоїх,
Доброта порятує світ.

Казка чудова, пісня неспинна
На світанку луна солов''їна...
Пісні і танцю свято натхненне,
То назавжди радість для мене...

Приспів.

Чую друга теплі долоні,
В серце лине лагідний промінь.
Музика мрії душу зігріє
І розквітне добра надія!..

Приспів','[''pisni.org.ua'', ''cat:all-ukraine'', ''Загальноукраїнські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5337747'), datetime('now')),datetime('now'));
