INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_533209','Немає хліба-співай','Музика: Гайдамаки Слова: Олександр Ярмола. Виконує: Гайдамаки','uk','ukraine_1991',NULL,NULL,'http://www.haydamaky.com/',NULL,'1.
Немає хліба - співай!
Немає хати - ходи, гуляй!
Голий, голодний, але свободний!
Душа по Смерті попаде в Рай.

Не маєш мови - мовчи!
Потратив гонор - сиди, дрочи!
Лихо Тобі! Не чуєш Кохання - спи,
Побачиш солодкі сни.

2.
Хто хоче жити, тіка.
Тече поволі людей ріка.
А Ти, бродяго, Богові дякуй,
Що твоя доля не така.

Що не такий як усі,
Не робиш як твій сусід.
Як важаєш, не мовчиш, нe ховаєшся, не спиш,
Не чуєш правди, - кричиш!

3.
Тобі закону нема,
Твоя країна Тобі - тюрма.
Не убий, не кради, а як украв, - не попади:
Мораль, з дитинства Тобі знайома.

Немає хліба - співай!
Немає каси, - ходи, гуляй!
Голий, голодний, за те - свободний,
Душа по Смерті попаде в Рай!','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_533209'), datetime('now')),datetime('now'));
