INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5333807','Різдвяна музика щастя','Музика: Сергій Родько Слова: Алла Бінцаровська. Виконує: Гурт Струни Серця','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Грають музику дивну
Заметілі-хурделі,
Наче флейти чарівні,
Наче віолончелі.
У незнані висоти
Линуть звуки органні,
Сяють золотом ноти,
Партитури різдвяні.

Приспів:
Хай несе новоріччя
Мрії нам не озорі!
Ми запалимо свічі,
Що засяють як зорі!
Хай пісні-віншування
Йдуть до кожного дому
І здійсняться бажання
Хай у Році Новому!

Зустрічає гостинно
Нас усіх Щедрий Вечір
І щаслива родина,
І радіє малеча!
Хай вогні ялинкові
Таємниче іскряться,
Хай звучить загадкова,
Тиха музика щастя!

Приспів.

І здійсняться бажання
Хай у Році Новому!','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5333807'), datetime('now')),datetime('now'));
