INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_533807','Щедрик Ведрик дайте Вареник','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Дитячі Щедрівки вигукуються розмірено або вимовляються говіркою. Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Радуйся Земле Коляда їде! Читати листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до інших листків про Українські традиції.','Щедрик-Ведрик дайте Вареник
Грудочку кашки кільце ковбаски
Як не даси ковбасу хату рознесу

Щедрик-Ведрик дайте Вареник
Грудочку кашки
А як мало дайте ще й сала
А як донесу дайте й ковбасу

Щедрик-Ведрик дайте Вареник
З руками з ногами щоб бігав за нами

