INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_531141','Котику Сіренький Котику Біленький','Українська народна пісня. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Колискові: Світові-Дитині. Еротика, жарти, забави: Катерини –... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... –... Ходить Котик по Плоточку. Котку Волохатий не ходи по Хаті. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові. Стежки до листків про Українські традиції. Пісні це наші отець-ненька. Пісні це наші діти. – Народна мудрість.','Котику Сіренький Котику Біленький
Котку Волохатий не ходи по Хаті
Не ходи по Хаті не буди Дитяти
Дитя буде спати Котик воркотати

Ой на Кота на Воркота
На Дитинку Дрімота
(А-а а-а а-а а)              | (2)

Ой ну люлі Котку не йди на Колодку
Не йди на Колодку бо заб''єш Головку
Та буде боліти нічим завертіти

Ой на Кота на Воркота
На Дитинку Дрімота
(А-а а-а а-а а)              | (2)

Ой-люлі-люлі
Люлі-люлі-люлі

Ой на Кота на Воркота
На Дитинку Дрімота
(А-а а-а а-а а)              | (2)','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:kolyskovi'', ''cat:narodni'', ''Дитячі пісні'', ''Колискові'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_531141'), datetime('now')),datetime('now'));
