INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_5341601','Мама','Музика: Анастасія Комлікова Слова: Анастасія Комлікова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Мама, мама -
Сонечко для синочка й донечки,
Мама, мама -
Квіточка ніжна й дорога,
Мама, мама - помічниця,
Мама, мама - рятівниця,
Чує кожен день і вечір
От такі слова:

Приспів:
Мамо, мамо, мамо, мамо,
Мамо, мамо, одягни!
Мамо, мамо, мамо, мамо,
Мамо, мамо, обійми!
Мамо, мамо, мамо, мамо,
Мамо, мамо, нагодуй!
Мамо, мамо, мамо, мамо,
Мамо, мамо, поцілуй!

Мама, мама -
Зіронька, калинова гілонька,
Мама, мама -
Пташечка, що голубить всіх,
Мама, мама - помічниця,
Мама, мама - рятівниця,
Що завжди почує голос
Діточок своїх.

Приспів.

Речитатив:
Візьми мене за руку, дорога матуся,
І з тобою я нічого не боюся!
Для мене ти найкраща у житті,
Люблю тебе , як любиш мене ти!
Мама! Мама! Мама! Мама! Мама!

Приспів.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_5341601'), datetime('now')),datetime('now'));
