INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_531405','Ішло Дівча Лучками','Українська народна пісня. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаївки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Кругом Нього зелененько всередині веселенько. Листки з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Гаїлка-Великдень — Українське Свято Відродження Світа. Стежки до інших листків про Українські традиції. Наша Дума, наша Пісня не вмре, не загине... От де Люде наша слава, слава України! Без золота, без каменю, без хитрої мови, А голосна та правдива як Господа Слово. – Тарас Шевченко. "До Основ''яненка".','Ішло Дівча Лучками
